import { computeModesPerStep, computeReachableSteps, nextRefsForMode, renderFlow, renderMarkdown, TARGETS, } from "bitfab-flow";
import { describe, expect, it } from "vitest";
import { setupFlow } from "./setup.js";
const TARGET_NAMES = ["claude", "cursor", "codex"];
function findStep(phaseId, stepId) {
    const phase = setupFlow.phases.find((p) => p.id === phaseId);
    if (phase === undefined) {
        throw new Error(`phase "${phaseId}" not found`);
    }
    const step = phase.steps.find((s) => s.id === stepId);
    if (step === undefined) {
        throw new Error(`step "${phaseId}/${stepId}" not found`);
    }
    return step;
}
describe("setupFlow schema invariants", () => {
    it("declares all eleven invocation modes with `wizard` as defaultMode", () => {
        expect(Object.keys(setupFlow.entries).sort()).toEqual([
            "db-snapshot",
            "explain",
            "inspect",
            "instrument",
            "login",
            "modify",
            "replay",
            "session-logs",
            "switch-org",
            "templates",
            "view",
            "wizard",
        ]);
        expect(setupFlow.defaultMode).toBe("wizard");
    });
    it("preamble is reachable only in `wizard` mode for every target", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const preambleModes = modesPerStep.get("preamble/render-intro");
            expect(preambleModes).toBeDefined();
            expect([...(preambleModes ?? [])]).toEqual(["wizard"]);
        }
    });
    it("login phase gates `wizard`, `login`, and `instrument` modes", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const loginStartModes = modesPerStep.get("login/status-check");
            expect(loginStartModes).toBeDefined();
            expect([...(loginStartModes ?? [])].sort()).toEqual([
                "instrument",
                "login",
                "wizard",
            ]);
        }
    });
    it("login/run-login failure path routes to cleanup", () => {
        const step = findStep("login", "run-login");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        const failureBranch = step.branches.find((b) => b.when === "login fails, errors, or times out" &&
            b.next === "cleanup/close-studio");
        expect(failureBranch).toBeDefined();
    });
    it.each(TARGET_NAMES)("tells %s to surface fresh Studio URLs from window-opened events", (targetName) => {
        const output = renderMarkdown(setupFlow, TARGETS[targetName]);
        expect(output).toContain('{"event":"window-opened","url":"..."}');
        expect(output).toContain("Studio opened: <url>");
        expect(output).toContain("even if the browser opened successfully");
    });
    it("instrument/search-existing 'Modify' option cross-phases to modify", () => {
        const step = findStep("instrument", "search-existing");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        const modifyBranch = step.branches.find((b) => b.option?.label === "Modify an existing trace setup");
        expect(modifyBranch).toBeDefined();
        expect(modifyBranch?.next).toBe("modify/gather-existing");
    });
    it("instrument/mandatory-stop D branch routes to replay only in `wizard` mode", () => {
        const step = findStep("instrument", "mandatory-stop");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        const aBranch = step.branches.find((b) => b.option?.letter === "A");
        expect(aBranch?.next).toBe("instrument/wait-for-trace");
        const dBranch = step.branches.find((b) => b.option?.letter === "D");
        expect(dBranch).toBeDefined();
        if (dBranch === undefined ||
            typeof dBranch.next === "string" ||
            dBranch.next === null) {
            throw new Error("expected byMode dispatch on D branch");
        }
        expect(dBranch.next.byMode.wizard).toBe("replay/gather-keys");
        expect(dBranch.next.byMode.instrument).toBe("cleanup/close-studio");
        expect(dBranch.next.byMode.login).toBe("cleanup/close-studio");
        expect(dBranch.next.byMode.modify).toBe("cleanup/close-studio");
        expect(dBranch.next.byMode.replay).toBe("cleanup/close-studio");
        expect(dBranch.next.byMode.explain).toBe("cleanup/close-studio");
        expect(dBranch.next.byMode.inspect).toBe("cleanup/close-studio");
    });
    it("instrument waits for a trace, then asks whether to replay that exact trace", () => {
        const wait = findStep("instrument", "wait-for-trace");
        expect(wait.kind).toBe("branch");
        if (wait.kind !== "branch") {
            throw new Error("unreachable");
        }
        expect(wait.commandCalls).toContain("waitForTrace");
        const found = wait.branches.find((b) => b.when?.includes('"found"'));
        expect(found?.next).toBe("instrument/offer-replay-after-trace");
        const offer = findStep("instrument", "offer-replay-after-trace");
        expect(offer.kind).toBe("branch");
        if (offer.kind !== "branch") {
            throw new Error("unreachable");
        }
        expect(offer.body).toMatch(/--trace-ids <traceId>/);
        const tryReplay = offer.branches.find((b) => b.option?.letter === "A");
        expect(tryReplay?.option?.label).toBe("Try replay now");
        expect(tryReplay?.next).toBe("instrument/run-single-trace-replay");
        const run = findStep("instrument", "run-single-trace-replay");
        expect(run.kind).toBe("action");
        if (run.kind !== "action") {
            throw new Error("unreachable");
        }
        expect(run.toolCalls).toContain("bash");
        expect(run.body).toMatch(/--trace-ids <traceId>/);
        expect(run.next).toBe("instrument/post-trace-replay-next-move");
    });
    it("replay/safety-net falls through to cleanup when every function is invocable", () => {
        const step = findStep("replay", "safety-net");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        // The A/B/C options only fire when a function is un-invocable; the common
        // "everything callable" path must be an explicit `when` arm to cleanup, or
        // the split-chain dead-ends without running closeStudio.js.
        const fallThrough = step.branches.find((b) => b.option === undefined && b.when !== undefined);
        expect(fallThrough).toBeDefined();
        expect(fallThrough?.next).toBe("cleanup/close-studio");
    });
    it("switch-org/perform-switch routes not-member/error to cleanup, not a prose stop", () => {
        const step = findStep("switch-org", "perform-switch");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        const failureArm = step.branches.find((b) => b.when?.includes("not-member"));
        expect(failureArm).toBeDefined();
        expect(failureArm?.next).toBe("cleanup/close-studio");
        const successArm = step.branches.find((b) => b.when?.includes("switched"));
        expect(successArm?.next).toBe("switch-org/update-local-env");
    });
    it("replay phase is unreachable in `instrument` mode (D exits the loop)", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const replayStartModes = modesPerStep.get("replay/gather-keys");
            expect(replayStartModes).toBeDefined();
            expect([...(replayStartModes ?? [])].sort()).toEqual(["replay", "wizard"]);
        }
    });
    it("modify phase is reachable in `wizard`, `instrument`, and `modify` modes", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const modifyStartModes = modesPerStep.get("modify/gather-existing");
            expect(modifyStartModes).toBeDefined();
            expect([...(modifyStartModes ?? [])].sort()).toEqual([
                "instrument",
                "modify",
                "wizard",
            ]);
        }
    });
    it("explain phase is reachable only in `explain` mode", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const explainModes = modesPerStep.get("explain/overview");
            expect(explainModes).toBeDefined();
            expect([...(explainModes ?? [])].sort()).toEqual(["explain"]);
        }
    });
    it("inspect phase is reachable only in `inspect` mode", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const inspectModes = modesPerStep.get("inspect/status-check");
            expect(inspectModes).toBeDefined();
            expect([...(inspectModes ?? [])].sort()).toEqual(["inspect"]);
        }
    });
    it("db-snapshot phase is reachable only in `db-snapshot` mode", () => {
        for (const targetName of TARGET_NAMES) {
            const modesPerStep = computeModesPerStep(setupFlow, targetName);
            const startModes = modesPerStep.get("db-snapshot/preflight");
            expect(startModes).toBeDefined();
            expect([...(startModes ?? [])].sort()).toEqual(["db-snapshot"]);
        }
    });
    it("registers the get_database_connection_status MCP tool and polls it in await-connection", () => {
        expect(setupFlow.tools.dbConnectionStatus).toEqual({
            kind: "mcp",
            name: "get_database_connection_status",
        });
        const connect = findStep("db-snapshot", "connect-db");
        expect(connect.toolCalls).toContain("dbConnectionStatus");
        const await_ = findStep("db-snapshot", "await-connection");
        expect(await_.toolCalls).toContain("dbConnectionStatus");
    });
    it("db-snapshot/await-connection loops on `checking` and exits to wire-replay on `connected`", () => {
        const step = findStep("db-snapshot", "await-connection");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        const connected = step.branches.find((b) => b.when === "status is connected");
        expect(connected?.next).toBe("db-snapshot/wire-replay");
        const checking = step.branches.find((b) => b.when === "status is checking");
        expect(checking?.next).toBe("db-snapshot/await-connection");
    });
    it("db-snapshot wires ReplayEnvironment per language and has no capture-config step (capture is always-on)", () => {
        const phase = setupFlow.phases.find((p) => p.id === "db-snapshot");
        expect(phase?.steps.some((s) => s.id === "enable-snapshot")).toBe(false);
        const wire = findStep("db-snapshot", "wire-replay");
        expect(wire.body).toMatch(/new ReplayEnvironment\(\)/); // TypeScript
        expect(wire.body).toMatch(/environment=env/); // Python
        expect(wire.body).toMatch(/Bitfab::ReplayEnvironment\.new/); // Ruby
        const smoke = findStep("db-snapshot", "smoke-test");
        expect(smoke.kind).toBe("action");
        if (smoke.kind !== "action") {
            throw new Error("unreachable");
        }
        expect(smoke.next).toBe("cleanup/close-studio");
    });
    it("modify/reconstruct-current-plan calls getTracePlan to bootstrap from a prior plan", () => {
        const step = findStep("modify", "reconstruct-current-plan");
        expect(step.toolCalls).toContain("getTracePlan");
        expect(step.body).toMatch(/traceFunctionKey/);
    });
    it("modify/build-modified-plan requires surrounding callers + callees as pure context", () => {
        const step = findStep("modify", "build-modified-plan");
        expect(step.body).toMatch(/~10 callers above/);
        expect(step.body).toMatch(/~10 callees below/);
        expect(step.body).toMatch(/`pure`/);
    });
    it("modify/present-diff routes Trace plan cancelled to the modifications branch (not terminate)", () => {
        const step = findStep("modify", "present-diff");
        expect(step.kind).toBe("branch");
        if (step.kind !== "branch") {
            throw new Error("unreachable");
        }
        expect(step.toolCalls).toContain("createTracePlan");
        expect(step.toolCalls).toContain("getTracePlan");
        const proceed = step.branches.find((b) => b.option?.letter === "A");
        expect(proceed?.next).toBe("modify/apply-changes");
        const modifications = step.branches.find((b) => b.option?.letter === "C");
        expect(modifications?.option?.label).toBe("Modifications");
        expect(modifications?.next).toBe("modify/build-modified-plan");
        const abort = step.branches.find((b) => b.option?.letter === "D");
        expect(abort?.option?.label).toBe("Abort entirely");
        expect(abort?.next).toBe("cleanup/close-studio");
        expect(step.body).toMatch(/"event":"cancelled".*branch \*\*C\*\*/s);
    });
    it("instrument/build-trace-plan passes traceFunctionKey to create_trace_plan", () => {
        const step = findStep("instrument", "build-trace-plan");
        expect(step.body).toMatch(/traceFunctionKey/);
        expect(step.body).toMatch(/~10 callers above/);
        expect(step.body).toMatch(/~10 callees below/);
    });
    it("declares the `reference` appendix consulted by build-trace-plan and build-modified-plan", () => {
        expect(setupFlow.appendices.find((a) => a.id === "reference")).toBeDefined();
        const buildTracePlan = findStep("instrument", "build-trace-plan");
        const buildModifiedPlan = findStep("modify", "build-modified-plan");
        expect(buildTracePlan.kind).toBe("reference");
        expect(buildModifiedPlan.kind).toBe("reference");
        if (buildTracePlan.kind === "reference") {
            expect(buildTracePlan.refs).toEqual(["reference"]);
        }
        if (buildModifiedPlan.kind === "reference") {
            expect(buildModifiedPlan.refs).toEqual(["reference"]);
        }
    });
    it("every step is reachable in some (mode, target) combination", () => {
        const allStepIds = new Set();
        for (const phase of setupFlow.phases) {
            for (const step of phase.steps) {
                allStepIds.add(`${phase.id}/${step.id}`);
            }
        }
        const reachableUnion = new Set();
        for (const targetName of TARGET_NAMES) {
            for (const id of computeReachableSteps(setupFlow, targetName)) {
                reachableUnion.add(id);
            }
        }
        expect([...reachableUnion].sort()).toEqual([...allStepIds].sort());
    });
});
describe("renderMarkdown(setupFlow)", () => {
    it("renders without throwing for every target", () => {
        for (const targetName of TARGET_NAMES) {
            const target = TARGETS[targetName];
            expect(() => renderMarkdown(setupFlow, target)).not.toThrow();
        }
    });
    it("preamble ASCII diagram appears in every target's rendered output", () => {
        for (const targetName of TARGET_NAMES) {
            const rendered = renderMarkdown(setupFlow, TARGETS[targetName]);
            expect(rendered).toContain("CODE");
            expect(rendered).toContain("TRACES");
            expect(rendered).toContain("DATASETS");
            expect(rendered).toContain("IMPROVE");
        }
    });
    it("codex output contains the BITFAB_PLUGIN_DIR resolution block; non-codex does not", () => {
        const codex = renderMarkdown(setupFlow, TARGETS.codex);
        expect(codex).toContain("BITFAB_PLUGIN_DIR=$(");
        expect(codex).toContain("CODEX_HOME");
        const claude = renderMarkdown(setupFlow, TARGETS.claude);
        expect(claude).not.toContain("CODEX_HOME");
        const cursor = renderMarkdown(setupFlow, TARGETS.cursor);
        expect(cursor).not.toContain("CODEX_HOME");
    });
    it("codex output uses 'ask the user' framing where claude/cursor use AskUserQuestion", () => {
        const codex = renderMarkdown(setupFlow, TARGETS.codex);
        const claude = renderMarkdown(setupFlow, TARGETS.claude);
        expect(claude).toContain("AskUserQuestion");
        expect(codex).not.toContain("Use `AskUserQuestion`");
        expect(codex).toContain("Ask the user");
    });
    it("apiKey MCP tool name reflects the target prefix", () => {
        expect(renderMarkdown(setupFlow, TARGETS.claude)).toContain("mcp__plugin_bitfab_Bitfab__get_bitfab_api_key");
        expect(renderMarkdown(setupFlow, TARGETS.cursor)).toContain("mcp__Bitfab__get_bitfab_api_key");
        expect(renderMarkdown(setupFlow, TARGETS.codex)).toContain("mcp__Bitfab__get_bitfab_api_key");
    });
});
describe("split-chain dispatch integrity", () => {
    const STEP_BY_ID = new Map();
    for (const phase of setupFlow.phases) {
        for (const step of phase.steps) {
            STEP_BY_ID.set(`${phase.id}/${step.id}`, step);
        }
    }
    function entryStart(entry) {
        if (typeof entry === "string") {
            return entry;
        }
        const resolved = entry.claude ?? entry.default;
        if (resolved === undefined) {
            throw new Error("entry has no resolvable start step");
        }
        return resolved;
    }
    function walkChain(mode, start) {
        const visited = new Set();
        const terminals = new Set();
        const queue = [start];
        while (queue.length > 0) {
            const id = queue.shift();
            if (id === null || id === undefined || visited.has(id)) {
                continue;
            }
            visited.add(id);
            const step = STEP_BY_ID.get(id);
            if (step === undefined) {
                throw new Error(`mode "${mode}": Next ref "${id}" has no matching step`);
            }
            const refs = nextRefsForMode(step, mode);
            if (refs.every((ref) => ref === null)) {
                terminals.add(id);
            }
            for (const ref of refs) {
                queue.push(ref);
            }
        }
        return { visited, terminals };
    }
    it("every Next ref in every mode resolves to a real step or null", () => {
        const validIds = new Set(STEP_BY_ID.keys());
        for (const mode of Object.keys(setupFlow.entries)) {
            for (const [id, step] of STEP_BY_ID) {
                for (const ref of nextRefsForMode(step, mode)) {
                    if (ref !== null) {
                        expect(validIds.has(ref), `mode "${mode}" step "${id}" routes to missing step "${ref}"`).toBe(true);
                    }
                }
            }
        }
    });
    it("every mode's dispatch chain converges on cleanup/close-studio as its only terminal", () => {
        for (const [mode, entry] of Object.entries(setupFlow.entries)) {
            const { visited, terminals } = walkChain(mode, entryStart(entry));
            expect(visited.has("cleanup/close-studio"), `mode "${mode}" never reaches cleanup/close-studio`).toBe(true);
            expect([...terminals].sort(), `mode "${mode}" has unexpected terminal steps`).toEqual(["cleanup/close-studio"]);
        }
    });
    it("wizard chains preamble -> login -> instrument -> replay -> cleanup; instrument mode skips replay", () => {
        const wizard = walkChain("wizard", entryStart(setupFlow.entries.wizard)).visited;
        for (const id of [
            "preamble/render-intro",
            "login/status-check",
            "instrument/detect-language",
            "replay/gather-keys",
            "cleanup/close-studio",
        ]) {
            expect(wizard.has(id), `wizard chain missing "${id}"`).toBe(true);
        }
        const instrument = walkChain("instrument", entryStart(setupFlow.entries.instrument)).visited;
        expect(instrument.has("instrument/detect-language")).toBe(true);
        expect(instrument.has("replay/gather-keys"), "instrument mode must NOT fall through into the replay phase").toBe(false);
    });
});
describe("rendered output hygiene", () => {
    const EXPECTED_FILE_COUNT = {
        claude: 14,
        cursor: 1,
        codex: 1,
    };
    it("renderFlow leaves no unresolved {{...}} template tokens in any file", () => {
        for (const targetName of TARGET_NAMES) {
            const files = renderFlow(setupFlow, TARGETS[targetName]);
            for (const file of files) {
                const leftover = file.content.match(/\{\{[^}]*\}\}/g);
                expect(leftover, `target "${targetName}" file "${file.slug || file.kind}" has unresolved tokens: ${leftover?.join(", ")}`).toBeNull();
            }
        }
    });
    it("compiles claude to an orchestrator + per-phase sub-skills, cursor/codex to a monolith", () => {
        for (const targetName of TARGET_NAMES) {
            const files = renderFlow(setupFlow, TARGETS[targetName]);
            expect(files.length, `target "${targetName}" produced an unexpected number of files`).toBe(EXPECTED_FILE_COUNT[targetName]);
        }
        const claudeKinds = renderFlow(setupFlow, TARGETS.claude).map((f) => f.kind);
        expect(claudeKinds.filter((kind) => kind === "orchestrator")).toHaveLength(1);
        expect(claudeKinds.filter((kind) => kind === "phase")).toHaveLength(13);
        expect(renderFlow(setupFlow, TARGETS.cursor)[0].kind).toBe("monolith");
        expect(renderFlow(setupFlow, TARGETS.codex)[0].kind).toBe("monolith");
    });
});
